import React, { useState, useEffect } from 'react';
import { API_BASE_URL } from '../config';
import { 
  Calendar, Clock, FileText, User, Users, ChevronDown, Home, UserCircle, 
  Calendar as CalendarIcon, Eye, EyeOff, Hospital, Stethoscope, Activity, 
  DollarSign, UserPlus, ShieldCheck, Users2, HeartPulse, Bed, TrendingUp,
  BarChart3, AlertTriangle, CheckCircle2, Zap, Smartphone, Monitor
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Button = ({ children, variant = 'primary', size = 'md', className = '', icon: Icon, ...props }) => {
  const baseClasses = `group inline-flex items-center justify-center font-semibold rounded-2xl transition-all duration-300 transform hover:scale-105 focus:outline-none focus:ring-4 focus:ring-offset-2 shadow-lg gap-2 border-0`;

  const variants = {
    primary: 'bg-gradient-to-r from-blue-600 to-blue-700 text-white hover:from-blue-700 hover:to-blue-800 focus:ring-blue-500 shadow-blue-500/25 hover:shadow-xl',
    secondary: 'bg-gradient-to-r from-emerald-500 to-emerald-600 text-white hover:from-emerald-600 hover:to-emerald-700 focus:ring-emerald-500 shadow-emerald-500/25 hover:shadow-xl',
    outline: 'border-2 border-white/30 text-white/90 bg-white/10 backdrop-blur-sm hover:bg-white/20 focus:ring-white/50 hover:shadow-lg',
    ghost: 'text-white/90 hover:text-white hover:bg-white/20 backdrop-blur-sm focus:ring-white/50'
  };

  const sizes = {
    sm: 'px-4 py-2 text-sm',
    md: 'px-6 py-3 text-base',
    lg: 'px-8 py-4 text-lg'
  };

  return (
    <button
      className={`${baseClasses} ${variants[variant]} ${sizes[size]} ${className}`}
      {...props}
    >
      {Icon && <Icon className="w-4 h-4 group-hover:translate-x-1 transition-transform" />}
      {children}
    </button>
  );
};

const Card = ({ children, className = '', hover = true }) => (
  <div className={`bg-white/80 backdrop-blur-xl rounded-3xl shadow-xl border border-white/50 overflow-hidden transition-all duration-500 ${
    hover ? 'hover:shadow-2xl hover:-translate-y-2 hover:bg-white' : ''
  } ${className}`}>
    {children}
  </div>
);

const CardHeader = ({ children, icon: Icon, title, subtitle }) => (
  <div className="bg-gradient-to-r from-blue-50/50 to-indigo-50/50 backdrop-blur-sm px-8 py-8 border-b border-white/50 relative overflow-hidden">
    <div className="absolute inset-0 bg-gradient-to-r from-blue-500/5 to-purple-500/5"></div>
    <div className="relative z-10 flex items-start space-x-4">
      {Icon && (
        <div className="w-16 h-16 bg-gradient-to-r from-blue-500 to-blue-600 rounded-2xl flex items-center justify-center shadow-lg flex-shrink-0">
          <Icon className="w-8 h-8 text-white" />
        </div>
      )}
      <div>
        <h3 className="text-2xl font-black bg-gradient-to-r from-gray-900 to-gray-700 bg-clip-text text-transparent mb-1">
          {title}
        </h3>
        {subtitle && <p className="text-gray-600 font-medium">{subtitle}</p>}
      </div>
    </div>
    {children}
  </div>
);

const CardTitle = ({ children }) => (
  <h3 className="text-2xl font-black bg-gradient-to-r from-gray-900 to-gray-700 bg-clip-text text-transparent">
    {children}
  </h3>
);

const CardContent = ({ children, className = '' }) => (
  <div className={`p-8 ${className}`}>
    {children}
  </div>
);

const CardFooter = ({ children, className = '' }) => (
  <div className={`px-8 py-6 bg-gradient-to-r from-gray-50/50 to-white/50 border-t border-white/50 ${className}`}>
    {children}
  </div>
);

const StatCard = ({ icon: Icon, title, value, change, trend = 'up' }) => (
  <Card className="group overflow-hidden relative">
    <div className="absolute inset-0 bg-gradient-to-br from-blue-500/5 to-purple-500/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
    <div className="p-8 relative z-10">
      <div className="flex items-center justify-between mb-4">
        <div className="p-4 bg-gradient-to-r from-blue-500 to-blue-600 rounded-2xl shadow-lg group-hover:scale-110 transition-all duration-300">
          <Icon className="w-6 h-6 text-white" />
        </div>
        <div className={`text-sm font-semibold px-3 py-1 rounded-full ${
          trend === 'up' 
            ? 'bg-emerald-100 text-emerald-800' 
            : 'bg-red-100 text-red-800'
        }`}>
          {change}
        </div>
      </div>
      <div className="text-4xl font-black bg-gradient-to-r from-gray-900 to-gray-700 bg-clip-text text-transparent mb-1">
        {value}
      </div>
      <p className="text-gray-600 font-medium">{title}</p>
    </div>
  </Card>
);

const Input = ({ label, icon: Icon, error, className = '', ...props }) => (
  <div className="space-y-2">
    <label className="block text-sm font-semibold text-gray-700 mb-2 flex items-center gap-2">
      {Icon && <Icon className="w-4 h-4 text-blue-600" />}
      {label}
    </label>
    <div className="relative">
      <input
        className={`w-full px-4 py-4 bg-white/50 backdrop-blur-sm border-2 rounded-2xl shadow-sm focus:outline-none focus:ring-4 focus:ring-blue-500/50 focus:border-blue-500 transition-all duration-300 text-lg placeholder-gray-400 ${
          error ? 'border-red-400 focus:border-red-500 focus:ring-red-500/50' : 'border-gray-200 hover:border-gray-300'
        } ${className}`}
        {...props}
      />
    </div>
    {error && <p className="text-sm text-red-500 mt-1 flex items-center gap-1">
      <AlertTriangle className="w-4 h-4" />
      {error}
    </p>}
  </div>
);

const Select = ({ label, icon: Icon, children, className = '', ...props }) => (
  <div className="space-y-2">
    <label className="block text-sm font-semibold text-gray-700 mb-2 flex items-center gap-2">
      {Icon && <Icon className="w-4 h-4 text-blue-600" />}
      {label}
    </label>
    <div className="relative">
      <select
        className="w-full px-4 py-4 bg-white/50 backdrop-blur-sm border-2 border-gray-200 rounded-2xl shadow-sm focus:outline-none focus:ring-4 focus:ring-blue-500/50 focus:border-blue-500 transition-all duration-300 text-lg appearance-none cursor-pointer"
        {...props}
      >
        {children}
      </select>
      <ChevronDown className="w-5 h-5 text-gray-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
    </div>
  </div>
);

const PasswordInput = ({ label, value, onChange, error, showPassword, togglePassword }) => (
  <div className="space-y-2">
    <label className="block text-sm font-semibold text-gray-700 mb-2">{label}</label>
    <div className="relative">
      <input
        type={showPassword ? "text" : "password"}
        value={value}
        onChange={onChange}
        className={`w-full px-4 py-4 pr-12 bg-white/50 backdrop-blur-sm border-2 rounded-2xl shadow-sm focus:outline-none focus:ring-4 focus:ring-blue-500/50 focus:border-blue-500 transition-all duration-300 text-lg placeholder-gray-400 ${
          error ? 'border-red-400 focus:border-red-500 focus:ring-red-500/50' : 'border-gray-200 hover:border-gray-300'
        }`}
      />
      <Button
        type="button"
        variant="ghost"
        size="sm"
        className="absolute right-3 top-1/2 -translate-y-1/2 h-10 w-10 p-0 hover:bg-white/20"
        onClick={togglePassword}
      >
        {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
      </Button>
    </div>
  </div>
);

const TabButton = ({ children, active, onClick, icon: Icon }) => (
  <button
    onClick={onClick}
    className={`group relative px-8 py-4 font-bold rounded-2xl transition-all duration-300 flex items-center gap-3 ${
      active
        ? 'bg-white text-blue-600 shadow-2xl shadow-blue-500/25 scale-105'
        : 'text-white/90 hover:text-white hover:bg-white/20 backdrop-blur-sm hover:shadow-xl hover:scale-105'
    }`}
  >
    {Icon && <Icon className={`w-5 h-5 ${active ? 'text-blue-600' : 'text-white/70 group-hover:text-white'}`} />}
    <span>{children}</span>
    {active && (
      <div className="absolute inset-0 bg-gradient-to-r from-blue-500/20 to-purple-500/20 -inset-1 rounded-2xl blur opacity-75 animate-pulse"></div>
    )}
  </button>
);

const AdminDashboard = () => {
  const [showDoctors, setShowDoctors] = useState(false);
  const [showPatients, setShowPatients] = useState(false);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isEditing, setIsEditing] = useState(false);
  const [adminInfo, setAdminInfo] = useState(null);
  const [editedInfo, setEditedInfo] = useState(null);
  const [doctorData, setDoctorData] = useState({
    firstName: '', lastName: '', email: '', specialty: '', licenseNumber: '', phoneNumber: '', password: ''
  });
  const [adminData, setAdminData] = useState({
    firstName: '', lastName: '', email: '', password: '', confirmPassword: ''
  });
  const [showDoctorPassword, setShowDoctorPassword] = useState(false);
  const [showAdminPassword, setShowAdminPassword] = useState(false);
