        { name: 'Dr. Rachel Kim', specialty: 'Pediatrics', patients: 52 }
      ]);
      setPatientOverview([
        { name: 'John Smith', appointments: 3 },
        { name: 'Maria Gonzalez', appointments: 1 },
        { name: 'David Wilson', appointments: 5 }
      ]);
    }, 500);
  }, []);

  const renderDashboard = () => {
    const occupancyRate = ((totalPatients / hospitalCapacity) * 100).toFixed(1);
    return (
      <div className="space-y-8">
        {/* Stats Grid */}
