                { icon: CheckCircle2, text: "Patient discharge batch completed", time: "5 hrs ago" }
              ].map((activity, idx) => (
                <div key={idx} className="flex items-start space-x-4 p-4 rounded-2xl bg-gradient-to-r from-gray-50 to-white hover:shadow-md transition-all group">
                  <activity.icon className="w-6 h-6 text-blue-600 mt-0.5 flex-shrink-0" />
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-gray-900 group-hover:text-blue-600 transition-colors">{activity.text}</p>
                    <p className="text-sm text-gray-500">{activity.time}</p>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>

          <Card>
            <CardHeader icon={CalendarIcon} title="Upcoming Tasks" />
            <CardContent className="space-y-4">
                           {[
                { icon: Calendar, text: "Staff performance review", due: "Next week", priority: "high" },
                { icon: FileText, text: "Update hospital policies", due: "Due in 3 days", priority: "medium" },
                { icon: Users, text: "Department heads meeting", due: "Tomorrow, 10:00 AM", priority: "high" },
                { icon: ShieldCheck, text: "Security audit review", due: "This Friday", priority: "low" }
              ].map((task, idx) => (
                <div key={idx} className={`p-6 rounded-2xl border-l-4 transition-all hover:shadow-md ${
                  task.priority === 'high' 
                    ? 'border-emerald-500 bg-emerald-50/50' 
