                        task.priority === 'high' ? 'text-emerald-600' :
                        task.priority === 'medium' ? 'text-amber-600' : 'text-blue-600'
                      }`} />
                      <p className="font-semibold text-gray-900 leading-relaxed">{task.text}</p>
                    </div>
                    <span className="text-sm font-semibold px-3 py-1 rounded-full bg-white/60 backdrop-blur-sm text-gray-700">
                      {task.due}
                    </span>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
        </div>
      </div>
