    };

    return (
      <Card className="max-w-4xl mx-auto">
        <CardHeader icon={UserCircle} title="Admin Profile" subtitle="Update your personal information" />
        <CardContent>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
