              <Input
                label="Last Name"
                name="lastName"
                value={isEditing ? editedInfo.lastName : adminInfo.lastName}
                onChange={handleInputChange}
                disabled={!isEditing}
              />
            </div>
            <div className="space-y-6">
              <Input
                label="Email Address"
                type="email"
                name="email"
                value={isEditing ? editedInfo.email : adminInfo.email}
                onChange={handleInputChange}
                disabled={!isEditing}
              />
              <div className="p-8 bg-gradient-to-br from-blue-50 to-indigo-50 rounded-3xl border-2 border-dashed border-blue-200 text-center">
                <ShieldCheck className="w-16 h-16 text-blue-500 mx-auto mb-4 opacity-75" />
                <h4 className="text-xl font-bold text-gray-900 mb-2">Account Secured</h4>
                <p className="text-gray-600">Your account uses enterprise-grade encryption and 2FA protection</p>
              </div>
            </div>
          </div>
        </CardContent>
        <CardFooter className="flex flex-col sm:flex-row gap-4 justify-end">
          {isEditing ? (
            <>
              <Button variant="outline" size="lg" onClick={() => setIsEditing(false)}>
                Cancel
              </Button>
              <Button variant="primary" size="lg" onClick={handleSave} className="min-w-[140px]">
                Save Changes
              </Button>
