          </div>

          {activeTab === 'Dashboard' && renderDashboard()}
          {activeTab === 'Profile' && renderProfile()}
          {activeTab === 'Add Doctor' && renderAddDoctor()}
          {activeTab === 'Add Admin' && renderAddAdmin()}
